import { useState, useEffect } from "react";
import axios from "axios";
import LoginPage from "./pages/LoginPage";
import SignupPage from "./pages/SignupPage";
import ChatPage from "./pages/ChatPage";

function App() {
  const [user, setUser] = useState(null);
  const [page, setPage] = useState("login"); // default is login

  useEffect(() => {
    // Register service worker when app loads
    if ("serviceWorker" in navigator) {
      navigator.serviceWorker
        .register("/sw.js")
        .then(registration => {
          console.log("Service Worker registered:", registration);

          // Subscribe to push notifications once service worker is ready
          navigator.serviceWorker.ready.then(reg => {
            reg.pushManager
              .subscribe({
                userVisibleOnly: true,
                applicationServerKey: "<YOUR_VAPID_PUBLIC_KEY>" // replace with your actual VAPID public key
              })
              .then(subscription => {
                console.log("Push subscription:", subscription);

                // Send subscription to backend to save with user
                axios.post("http://localhost:5001/user/saveSubscription", {
                  subscription
                });
              })
              .catch(err =>
                console.error("Push subscription failed:", err)
              );
          });
        })
        .catch(err =>
          console.error("Service Worker registration failed:", err)
        );
    }
  }, []);

  return page === "signup" ? (
    <SignupPage setUser={setUser} setPage={setPage} />
  ) : page === "login" ? (
    <LoginPage setUser={setUser} setPage={setPage} />
  ) : (
    <ChatPage user={user} />
  );
}

export default App;
